#include <bits/stdc++.h>
using namespace std;
long long a[10]={1},f[1010],s=1,k,n;
int main(){
	cin>>k>>n;
	for(int i=1;i<=9;i++){
		a[i]=a[i-1]*k;
    }
	for(int i=0;i<=9;i++){
		f[s]=a[i];
		for(long long j=1;j<=s;j++){
			f[s+j]=f[s]+f[j];
        }
		s*=2;
		if(f[n]!=0){
			cout<<f[n];
			return 0;
		}
	}
	return 0;
}
